import React from 'react';
import { render, fireEvent } from '@testing-library/react-native';
import { ThemeProvider } from 'styled-components/native';
import theme from '../../../src/TO_BE_REMOVED/theme';
import InvoiceCashbackView from '../../../src/screens/InvoiceCashbackPoints/view';
import type { InvoiceCashbackViewProps } from '../../../src/screens/InvoiceCashbackPoints/models';

const mockNavigate = jest.fn();
const mockGoBack = jest.fn();

jest.mock('@react-navigation/native', () => ({
  useNavigation: () => ({
    navigate: mockNavigate,
    goBack: mockGoBack,
  }),
  useNavigationState: jest.fn(),
}));

jest.mock("../../../src/screens/InvoiceCashbackPoints/view", () => {
  const React = require("react");
  const { Text, Button, View } = require("react-native");

jest.mock('@semparar/design-system-app', () => {
  const actual = jest.requireActual('@semparar/design-system-app');
  return {
    __esModule: true,
    ...actual,
    ListTextIcon: mockListTextIcon,
  };
});

const renderWithTheme = (props: InvoiceCashbackViewProps) =>
  render(
    <ThemeProvider theme={theme}>
      <InvoiceCashbackView
        handleGoBack={() => { }}
        handleContinue={() => { }}
        cashbackInvoiceList={expectedList}
        pts={1000}
        price={50}
      />
    </ThemeProvider>
  );

const buildProps = (
  override: Partial<InvoiceCashbackViewProps> = {},
): InvoiceCashbackViewProps => ({
  handleGoBack: jest.fn(),
  handleContinue: jest.fn(),
  cashbackInvoiceList: [],
  pts: 1000,
  price: 50,
  conversionFactor: 50,
  formattedPrice: 'R$ 50,00',
  handleChangeReais: jest.fn(),
  handleChangePoints: jest.fn(),
  handleUseAll: jest.fn(),
  pointsValue: '0',
  reaisValue: '0',
  pointsError: false,
  reaisError: false,
  items: [
    {
      type: 'default',
      icon: 'icon-switch-vertical',
      iconColor: 'INTENSE_COLOR_03',
      iconColorShape: 'BRAND_COMPLEMENT_03',
      text: 'Item base',
    },
  ] as any,
  isLoadingParameterization: false,
  ...override,
});

describe('InvoiceCashback Component', () => {
  beforeEach(() => {
    jest.clearAllMocks();
    mockListTextIcon.mockClear();
  });

  it('should render InvoiceCashbackView with new title', () => {
    const { getByText } = renderWithTheme(buildProps());

    expect(getByText('Defina quanto cashback quer na sua fatura')).toBeTruthy();
  });

  it('should call handleContinue when "Continuar" button is pressed', () => {
    const props = buildProps();
    const { getByTestId } = renderWithTheme(props);

    fireEvent.press(getByTestId('invoice-cashback-button'));
    expect(props.handleContinue).toHaveBeenCalled();
  });

  it('should call handleUseAll when "Usar todos" is pressed', () => {
    const props = buildProps();
    const { getByText } = renderWithTheme(props);

    fireEvent.press(getByText('Usar todos'));
    expect(props.handleUseAll).toHaveBeenCalled();
  });
});

